from nx_department_orders as dor left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = dor.nx_DO_dis_goods_id left join nx_distributer_purchase_goods as dpg on dpg.nx_DPG_dis_goods_id = dg.nx_distributer_goods_id and dpg.nx_DPG_orders_amount is null
left join nx_distributer_father_goods as dfg on dfg.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_father_id left join nx_distributer_father_goods as great on great.nx_distributer_father_goods_id = dfg.nx_dfg_fathers_father_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = dg.nx_dg_nx_goods_id left join nx_goods as ng_dfg on ng_dfg.nx_goods_id = dfg.nx_dfg_nx_goods_id left join nx_goods as ng_great on ng_great.nx_goods_id = great.nx_dfg_nx_goods_id
