left join nx_distributer_purchase_goods as dpgOrder on dpgOrder.nx_DPG_dis_goods_id = dg.nx_distributer_goods_id and dpgOrder.nx_DPG_orders_amount is not null and dpgOrder.nx_DPG_status < 4 left join nx_department_orders as purDor on purDor.nx_DO_purchase_goods_id = dpgOrder.nx_distributer_purchase_goods_id and purDor.nx_DO_status < 3
