SELECT dor.nx_DO_department_father_id as depId, COUNT(CASE WHEN dor.nx_DO_status < 3 AND dor.nx_DO_status > -2 THEN 1 END) as count0, COUNT(CASE WHEN dor.nx_DO_status < 3 AND dor.nx_DO_purchase_status < 4 AND dor.nx_DO_status > -2 THEN 1 END) as count1, COUNT(CASE WHEN dor.nx_DO_status < 3 AND dor.nx_DO_purchase_status = 4 THEN 1 END) as count2 FROM nx_department_orders as dor
left join nx_distributer_purchase_goods as ndpg on ndpg.nx_distributer_purchase_goods_id = dor.nx_DO_purchase_goods_id left join nx_distributer_purchase_batch as ndpb on ndpb.nx_distributer_purchase_batch_id = ndpg.nx_DPG_batch_id
WHERE dor.nx_DO_department_father_id IN
#{depId}
and dor.nx_DO_purchase_goods_id is not null and ndpg.nx_DPG_batch_id is not null and ndpb.nx_DPB_supplier_id = #{params.nxSupplierId}
GROUP BY dor.nx_DO_department_father_id

SELECT nx_DO_department_father_id as `depFatherId`, COUNT(CASE WHEN nx_DO_status = -2 THEN 1 END ) as `unDo`, COUNT(CASE WHEN nx_DO_status < 3 and nx_DO_status > -2 AND nx_DO_price IS NOT NULL AND nx_DO_price != 0.1 THEN 1 END) as `hasPrice`, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_purchase_status > 3 THEN 1 END) as `hasWeight`, COUNT(CASE WHEN nx_DO_status < 3 and nx_DO_status > -2 THEN 1 END) as `totalCount`, COUNT(CASE WHEN nx_DO_status = 2 and nx_DO_purchase_status > 3 and nx_DO_price != 0.1 and nx_DO_subtotal > 0 THEN 1 END) as `finishCount`, SUM(CASE WHEN nx_DO_status = 2 and nx_DO_purchase_status > 3 THEN nx_DO_subtotal ELSE 0 END) as `totalSubtotal` FROM nx_department_orders WHERE nx_DO_department_father_id IN
#{depFatherId}
and nx_DO_collaborative_nx_dis_id = -1 GROUP BY nx_DO_department_father_id

SELECT nx_DO_gb_distributer_id as gbDisId, nx_DO_gb_department_father_id as gbDepId, COUNT(CASE WHEN nx_DO_status < 3 THEN 1 END) as newOrder, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_purchase_goods_id = 1 THEN 1 END) as jinhuoOrder, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_purchase_goods_id = -1 THEN 1 END) as chukuOrder, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_weight IS NULL THEN 1 END) as hasNotWeight, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_purchase_goods_id = 1 AND nx_DO_weight IS NOT NULL THEN 1 END) as jinhuoHasWeight, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_purchase_goods_id = -1 AND nx_DO_weight IS NOT NULL THEN 1 END) as chukuHasWeight, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_price IS NOT NULL THEN 1 END) as hasPrice, COUNT(CASE WHEN nx_DO_status < 3 AND nx_DO_price IS NULL THEN 1 END) as hasNotPrice, COUNT(CASE WHEN nx_DO_status = 2 THEN 1 END) as twoTotal, SUM(CASE WHEN nx_DO_status = 2 THEN nx_DO_subtotal ELSE 0 END) as total FROM nx_department_orders
AND nx_DO_gb_distributer_id IN
#{gbDisId}
AND nx_DO_gb_department_father_id IN
#{gbDepId}
GROUP BY nx_DO_gb_distributer_id, nx_DO_gb_department_father_id

SELECT dor.nx_DO_gb_department_father_id as depId, COUNT(CASE WHEN dor.nx_DO_status < 3 THEN 1 END) as count0, COUNT(CASE WHEN dor.nx_DO_status < 3 AND dor.nx_DO_purchase_status < 4 THEN 1 END) as count1, COUNT(CASE WHEN dor.nx_DO_status < 3 AND dor.nx_DO_purchase_status = 4 THEN 1 END) as count2 FROM nx_department_orders as dor
left join nx_distributer_purchase_goods as ndpg on ndpg.nx_distributer_purchase_goods_id = dor.nx_DO_purchase_goods_id left join nx_distributer_purchase_batch as ndpb on ndpb.nx_distributer_purchase_batch_id = ndpg.nx_DPG_batch_id
WHERE dor.nx_DO_gb_department_father_id IN
#{gbDepId}
