-- 货架商品基本信息 ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_shelf_layer_seq, ndgsg.nx_DGSG_shelf_layer_last,
-- 商品基本信息（只返回必要字段） ndg.nx_distributer_goods_id, ndg.nx_dg_goods_name, ndg.nx_dg_goods_standardname, ndg.nx_dg_goods_standard_weight, ndg.nx_dg_carton_unit, ndg.nx_dg_goods_brand, ndg.nx_dg_items_per_carton,
-- 订单基本信息（只返回必要字段） dor.nx_department_orders_id, dor.nx_DO_quantity, dor.nx_DO_standard, dor.nx_DO_print_standard, dor.nx_DO_weight, dor.nx_DO_remark, dor.nx_DO_print_standard, dor.nx_DO_collaborative_nx_dis_id,
-- 部门名称（扁平化字符串，使用 CONCAT 拼接） -- 当子部门的属性名称为空时，使用部门名称作为备选 CASE WHEN ndf.nx_department_attr_name IS NOT NULL AND ndf.nx_department_attr_name != '' THEN CONCAT(ndf.nx_department_attr_name, '.', COALESCE(NULLIF(nds.nx_department_attr_name, ''), nds.nx_department_name)) ELSE COALESCE(NULLIF(nds.nx_department_attr_name, ''), nds.nx_department_name) END as dep_name,
-- 部门属性名称（单独返回） -- 当子部门的属性名称为空时，使用部门名称作为备选 COALESCE( NULLIF(nds.nx_department_attr_name, ''), nds.nx_department_name ) as nx_department_attr_name,
