-- 协作配送商名称 COALESCE(nd_coll.nx_distributer_show_name, nd_coll.nx_distributer_name) as nx_do_collaborative_distributer_name
from nx_department_orders as dor left join nx_department as nds on nds.nx_department_id = dor.nx_DO_department_id left join nx_department as ndf on ndf.nx_department_id = nds.nx_department_father_id left join gb_department as ngds on ngds.gb_department_id = dor.nx_DO_gb_department_id left join gb_department as ngdf on ngdf.gb_department_id = dor.nx_DO_gb_department_father_id left join nx_restraunt as ndnr on ndnr.nx_restraunt_id = dor.nx_DO_nx_comm_restraunt_id left join nx_distributer as nd_coll on nd_coll.nx_distributer_id = dor.nx_DO_collaborative_nx_dis_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = dor.nx_DO_dis_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id left join nx_department_dis_goods as nddg on nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id and nddg.nx_DDG_department_id = dor.nx_DO_department_id
and ndgs.nx_distributer_goods_shelf_id = #{targetShelfId}
